          "jsCode": "const allItems = $input.all();\nconst sepContext = allItems\n  .filter(item => item.json.role)\n  .map(item => {\n    const role = item.json.role || 'unknown';\n    const content = item.json.content || '';\n    const ts = item.json.created_at ? new Date(item.json.created_at).toISOString() : '';\n    return `[${role.toUpperCase()}] ${ts}\\n${content}`;\n  })\n  .join('\\n\\n---\\n\\n');\nconst session = $('SESSION_RESOLVER').first().json;\nreturn [{\n  json: {\n    user_id: session.user_id,\n    thread_id: session.thread_id,\n    message: session.message,\n    timestamp: session.timestamp,\n    sep_context: sepContext,\n    sep_item_count: allItems.filter(item => item.json.role).length\n  },\n  pairedItem: { item: 0 }\n}];"
