      {
        "id": "xo-db-001",
        "name": "USER_UPSERT",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          550,
          400
        ],
        "parameters": {
          "operation": "executeQuery",
          "query": "=INSERT INTO utilisateurs (telegram_id, nom)\nVALUES ({{ $json.message.chat.id }}, $uname${{ $json.message.from.first_name }}$uname$)\nON CONFLICT (telegram_id) DO UPDATE SET updated_at = NOW()\nRETURNING utilisateur_id, telegram_id, nom;",
          "options": {}
        },
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "retryOnFail": true,
        "alwaysOutputData": true
      },
      {
        "id": "xo-db-002",
        "name": "SESSION_LOAD",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          850,
          400
        ],
        "parameters": {
          "operation": "executeQuery",
          "query": "=SELECT\n    u.utilisateur_id,\n    u.telegram_id,\n    p.projet_id,\n    p.hashtag AS projet_actif,\n    p.nom AS projet_nom,\n    p.brief_executif,\n    p.statut AS projet_statut,\n    s.session_id,\n    s.pole_actif,\n    s.etat AS session_etat,\n    s.resume_session,\n    COALESCE(recent_msgs.historique, '[]'::jsonb) AS historique_recent\nFROM utilisateurs u\nLEFT JOIN sessions s ON s.utilisateur_id = u.utilisateur_id\n    AND s.etat = 'ouvert'\n    AND s.last_activity > NOW() - INTERVAL '24 hours'\nLEFT JOIN projets p ON p.projet_id = s.projet_id\nLEFT JOIN LATERAL (\n    SELECT jsonb_agg(\n        jsonb_build_object('role', m.role, 'contenu', m.contenu, 'pole', m.pole_emetteur, 'ts', m.created_at)\n    ) AS historique\n    FROM (\n        SELECT role, contenu, pole_emetteur, created_at\n        FROM messages\n        WHERE session_id = s.session_id\n        ORDER BY created_at DESC\n        LIMIT 5\n    ) m\n) recent_msgs ON true\nWHERE u.telegram_id = {{ $json.telegram_id }}\nLIMIT 1;",
          "options": {}
        },
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "retryOnFail": true,
        "alwaysOutputData": true
      },
      {
        "id": "xo-code-001",
        "name": "CERVEAU_XO",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          1150,
          400
        ],
        "parameters": {
          "jsCode": "const telegramMsg = $('TELEGRAM_INPUT').item.json;\nconst text = (telegramMsg.message?.text || '').trim();\nconst sessionData = $json;\n\n// Extract hashtags\nconst hashtags = (text.match(/#(\\w+)/g) || []).map(h => h.slice(1).toLowerCase());\nconst poleHashtags = ['finance', 'marketing', 'strategie', 'produit', 'risk'];\nconst polesActives = hashtags.filter(h => poleHashtags.includes(h));\nconst projetHashtag = hashtags.find(h => !poleHashtags.includes(h));\n\n// Detect route\nlet route = 'agent';\nlet mode = 'dialogue';\n\nif (text.startsWith('/menu')) {\n  route = 'menu';\n} else if (text.startsWith('/reset') || text.toLowerCase() === 'reset') {\n  route = 'reset';\n} else if (!sessionData.session_id && !text.startsWith('/')) {\n  route = 'agent';\n  mode = 'qualification';\n} else if (text.toLowerCase().match(/j.ai une id[e\\u00e9]e|et si on|je veux cr[e\\u00e9]er|je veux d[e\\u00e9]velopper/)) {\n  route = 'agent';\n  mode = 'qualification';\n}\n\nreturn [{\n  json: {\n    telegram_chat_id: telegramMsg.message?.chat?.id,\n    routing: {\n      route,\n      mode,\n      poles_actives: polesActives.length > 0 ? polesActives : null,\n      projet_hashtag: projetHashtag || sessionData.projet_actif || null,\n      session_context: sessionData,\n      text_clean: text.replace(/#\\w+/g, '').trim()\n    }\n  }\n}];"
        }
      },
      {
        "id": "xo-sw-001",
        "name": "ROUTER",
        "type": "n8n-nodes-base.switch",
        "typeVersion": 3.4,
        "position": [
          1450,
          400
        ],
        "parameters": {
          "rules": {
            "values": [
              {
                "conditions": {
                  "options": {
                    "caseSensitive": true,
                    "leftValue": "",
                    "typeValidation": "strict"
                  },
                  "combinator": "and",
                  "conditions": [
                    {
                      "id": "r1",
                      "leftValue": "={{ $json.routing.route }}",
                      "rightValue": "menu",
                      "operator": {
                        "type": "string",
                        "operation": "equals",
                        "name": "filter.operator.equals"
                      }
                    }
                  ]
                },
                "renameOutput": true,
                "outputKey": "menu"
              },
              {
                "conditions": {
                  "options": {
                    "caseSensitive": true,
                    "leftValue": "",
                    "typeValidation": "strict"
                  },
                  "combinator": "and",
                  "conditions": [
                    {
                      "id": "r2",
                      "leftValue": "={{ $json.routing.route }}",
                      "rightValue": "reset",
                      "operator": {
                        "type": "string",
                        "operation": "equals",
                        "name": "filter.operator.equals"
                      }
                    }
                  ]
                },
                "renameOutput": true,
                "outputKey": "reset"
              }
            ]
          },
          "options": {
            "fallbackOutput": "extra"
          }
        }
      },
      {
        "id": "xo-tg-002",
        "name": "MENU_HANDLER",
        "type": "n8n-nodes-base.telegram",
        "typeVersion": 1.2,
        "position": [
          1750,
          200
        ],
        "parameters": {
          "chatId": "={{ $json.telegram_chat_id }}",
          "text": "Menu K3rn.labs\n\nCommandes disponibles :\n/reset — Reinitialiser la session\n\nHashtags disponibles :\n#[nom_projet] — Activer un projet\n#finance #marketing #strategie #produit #risk — Activer un pole",
          "additionalFields": {}
        },
        "credentials": {
          "telegramApi": {
            "id": "phBnIaab9S8x5cOj",
            "name": "Telegram K3rn Bot"
          }
        }
      },
      {
        "id": "xo-db-003",
        "name": "RESET_HANDLER",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          1750,
          400
        ],
        "parameters": {
          "operation": "executeQuery",
          "query": "=UPDATE sessions SET etat = 'ferme', closed_at = NOW()\nWHERE utilisateur_id = (\n    SELECT utilisateur_id FROM utilisateurs\n    WHERE telegram_id = {{ $json.telegram_chat_id }}\n)\nAND etat = 'ouvert';",
          "options": {}
        },
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "alwaysOutputData": true,
        "retryOnFail": true
      },
      {
