        "name": "RESET_REPONSE",
        "type": "n8n-nodes-base.telegram",
        "typeVersion": 1.2,
        "position": [
          2050,
          400
        ],
        "parameters": {
          "chatId": "={{ $('CERVEAU_XO').item.json.telegram_chat_id }}",
          "text": "Session reinitia lisee. Pret pour un nouveau projet.",
          "additionalFields": {}
        },
        "credentials": {
          "telegramApi": {
            "id": "phBnIaab9S8x5cOj",
            "name": "Telegram K3rn Bot"
          }
        }
      },
      {
        "id": "xo-ai-002",
        "name": "XO_AGENT",
        "type": "@n8n/n8n-nodes-langchain.agent",
        "typeVersion": 3.1,
        "position": [
          1750,
          600
        ],
        "parameters": {
          "promptType": "define",
          "text": "=MODE : {{ $json.routing.mode }}\nPROJET ACTIF : {{ $json.routing.projet_hashtag || 'aucun' }}\nPOLES ACTIVES : {{ $json.routing.poles_actives || 'inference auto' }}\n\nCONTEXTE PROJET :\n{{ $('SESSION_LOAD').item.json.brief_executif || 'Aucun projet actif.' }}\n\nHISTORIQUE RECENT :\n{{ $('SESSION_LOAD').item.json.historique_recent || 'Premiere interaction.' }}\n\n---\n{{ $json.routing.text_clean }}",
          "options": {
            "systemMessage": "Tu es le Chief of Staff (XO) — bras droit executif du patron.\nTu diriges une organisation complete : Strategie, Finance, Marketing, Produit, Risk.\nTu es l unique interlocuteur. Le patron ne parle jamais aux poles directement.\n\nREGLES :\n- Dialogue naturel, professionnel, direct\n- Mode qualification : accueille l idee, reformule en 2-3 lignes, annonce l etape suivante (aucune question dans ce premier message)\n- Mode dialogue : reponds a la requete, active les poles pertinents si hashtag present\n- Maximum 1 question par message si clarification necessaire\n- Jamais de jargon technique expose (agents, workflows, nodes)\n- Si pas de projet actif et message ambigu : demande sur quel projet travailler\n- Ton : confiant, classe mondiale, sans remplissage",
            "maxIterations": 5,
            "timeout": 200000
          }
        }
      },
      {
        "id": "xo-db-004",
        "name": "DB_WRITE_SESSION",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          2050,
          600
        ],
        "parameters": {
          "operation": "executeQuery",
          "query": "=INSERT INTO sessions (utilisateur_id, pole_actif, etat)\nSELECT u.utilisateur_id, 'XO', 'ouvert'\nFROM utilisateurs u\nWHERE u.telegram_id = {{ $('CERVEAU_XO').item.json.telegram_chat_id }}\nAND NOT EXISTS (\n    SELECT 1 FROM sessions s2\n    WHERE s2.utilisateur_id = u.utilisateur_id\n    AND s2.etat = 'ouvert'\n    AND s2.last_activity > NOW() - INTERVAL '24 hours'\n);",
          "options": {}
        },
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        },
        "alwaysOutputData": true,
        "retryOnFail": true
