python3 -c "
import json

with open('/Users/user/.claude/projects/-Users-user-Desktop-N8N-consultant/3763bda5-42e3-4623-8658-e31529dbaf27/tool-results/mcp-n8n-mcp-n8n_get_workflow-1771876848790.txt', 'r') as f:
    raw = json.load(f)

data = json.loads(raw[0]['text'])
nodes = data['data']['nodes']

ops = []
for n in nodes:
    if n['type'] != '@n8n/n8n-nodes-langchain.toolHttpRequest':
        continue

    params = n['parameters']
    headers = params.get('parametersHeaders', {}).get('values', [])
    body = params.get('jsonBody', '')
    is_tavily = 'tavily' in n['name']

    # Corriger Content_Type → Content-Type
    new_headers = []
    changed = False
    for h in headers:
        if h['name'] == 'Content_Type':
            new_headers.append({**h, 'name': 'Content-Type'})
            changed = True
        else:
            new_headers.append(h)

    # Tavily: ajouter Authorization Bearer + retirer api_key du body
    if is_tavily:
        # Ajouter Bearer si pas déjà là
        has_bearer = any(h.get('name') == 'Authorization' for h in new_headers)
        if not has_bearer:
            new_headers.append({
                'name': 'Authorization',
                'valueProvider': 'fieldValue',
                'value': 'Bearer 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'
            })
            changed = True
        # Retirer api_key du body
        if 'api_key' in body:
            new_body = body.replace('\"api_key\": \"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\", ', '')
            changed = True
        else:
            new_body = body
    else:
        new_body = body

    if changed:
        new_params = {**params}
        new_params['parametersHeaders'] = {'values': new_headers}
        if is_tavily:
            new_params['jsonBody'] = new_body
        ops.append({
            'type': 'updateNode',
            'nodeId': n['id'],
            'updates': {'parameters': new_params}
        })

print(f'Total operations: {len(ops)}')
for op in ops:
    nname = next(n['name'] for n in nodes if n['id'] == op['nodeId'])
    print(f'  - {nname} ({op[\"nodeId\"]})')

# Sauvegarder les ops pour usage
with open('/tmp/ops_fix_toolhttp.json', 'w') as f:
    json.dump(ops, f, indent=2)
print('Saved to /tmp/ops_fix_toolhttp.json')
" 2>&1

