  {type: "addConnection", source: "Window Buffer Memory", target: "AI Agent", sourceOutput: "ai_memory"}
]})
```

```javascript
// Add fallback model to AI Agent for reliability
n8n_update_partial_workflow({id: "ai6", operations: [
  {type: "addConnection", source: "OpenAI Chat Model", target: "AI Agent", sourceOutput: "ai_languageModel", targetIndex: 0},
  {type: "addConnection", source: "Anthropic Chat Model", target: "AI Agent", sourceOutput: "ai_languageModel", targetIndex: 1}
]})
```

```javascript
// Vector Store setup: Connect embeddings and documents
n8n_update_partial_workflow({id: "ai7", operations: [
  {type: "addConnection", source: "Embeddings OpenAI", target: "Pinecone Vector Store", sourceOutput: "ai_embedding"},
