```javascript
// Rewire AI Agent to use different language model
n8n_update_partial_workflow({id: "ai9", operations: [{type: "rewireConnection", source: "AI Agent", from: "OpenAI Chat Model", to: "Anthropic Chat Model", sourceOutput: "ai_languageModel"}]})
```

```javascript
// Replace all AI tools for an agent
n8n_update_partial_workflow({id: "ai10", operations: [
  {type: "removeConnection", source: "Old Tool 1", target: "AI Agent", sourceOutput: "ai_tool"},
