          ],
          "parameters": {
            "promptType": "define",
            "text": "=MODE : {{ $json.routing?.mode || ($if($('POLE_DISPATCHER').isExecuted, $('POLE_DISPATCHER').item.json.pole_actif, '') ? 'pole' : 'dialogue') }}\nPROJET ACTIF : {{ $json.routing?.projet_hashtag || $if($('POLE_DISPATCHER').isExecuted, $('POLE_DISPATCHER').item.json.projet_hashtag, '') || 'aucun' }}\nPOLE : {{ $if($('POLE_DISPATCHER').isExecuted, $('POLE_DISPATCHER').item.json.pole_label, 'N/A') }}\n\n{{ $if($('POLE_DISPATCHER').isExecuted, $('POLE_DISPATCHER').item.json.pole_actif, '') ? 'RESULTATS POLE ' + $if($('POLE_DISPATCHER').isExecuted, $('POLE_DISPATCHER').item.json.pole_label, '') + ' :' : 'CONTEXTE PROJET :' }}\n{{ $if($('POLE_DISPATCHER').isExecuted, $('POLE_DISPATCHER').item.json.pole_actif, '') ? ($if($('POLE_SEARCH').isExecuted, $('POLE_SEARCH').item.json.choices[0].message.content, 'Aucun resultat.')) : ($('SESSION_LOAD').item.json.brief_executif || 'Aucun projet actif.') }}\n\nHISTORIQUE RECENT :\n{{ $('SESSION_LOAD').item.json.historique_recent || 'Premiere interaction.' }}\n\n---\n{{ $json.routing?.text_clean || $if($('POLE_DISPATCHER').isExecuted, $('POLE_DISPATCHER').item.json.query, '') }}",
            "hasOutputParser": false,
            "needsFallback": false,
