          "name": "SESSION_LOAD",
          "type": "n8n-nodes-base.postgres",
          "typeVersion": 2.6,
          "position": [
            850,
            400
          ],
          "parameters": {
            "operation": "executeQuery",
            "query": "=SELECT\n    u.utilisateur_id,\n    u.telegram_id,\n    p.projet_id,\n    p.hashtag AS projet_actif,\n    p.nom AS projet_nom,\n    p.brief_executif,\n    p.statut AS projet_statut,\n    s.session_id,\n    s.pole_actif,\n    s.etat AS session_etat,\n    s.resume_session,\n    COALESCE(recent_msgs.historique, '[]'::jsonb) AS historique_recent\nFROM utilisateurs u\nLEFT JOIN sessions s ON s.utilisateur_id = u.utilisateur_id\n    AND s.etat = 'ouvert'\n    AND s.last_activity > NOW() - INTERVAL '24 hours'\nLEFT JOIN projets p ON p.projet_id = s.projet_id\nLEFT JOIN LATERAL (\n    SELECT jsonb_agg(\n        jsonb_build_object('role', m.role, 'contenu', m.contenu, 'pole', m.pole_emetteur, 'ts', m.created_at)\n    ) AS historique\n    FROM (\n        SELECT role, contenu, pole_emetteur, created_at\n        FROM messages\n        WHERE session_id = s.session_id\n        ORDER BY created_at DESC\n        LIMIT 5\n    ) m\n) recent_msgs ON true\nWHERE u.telegram_id = {{ $json.telegram_id }}\nLIMIT 1;",
            "options": {}
