            "query": "=INSERT INTO projets (utilisateur_id, hashtag, nom, statut)\nSELECT \n    u.utilisateur_id,\n    ARRAY_TO_STRING(\n        (STRING_TO_ARRAY(\n            TRIM(\n                REGEXP_REPLACE(\n                    REGEXP_REPLACE(\n                        LOWER($ct${{ $('CERVEAU_XO').item.json.routing.text_clean }}$ct$),\n                        '[^a-z0-9 ]', '', 'g'\n                    ),\n                    '\\s+', ' ', 'g'\n                )\n            ),\n            ' '\n        ))[1:3],\n        '_'\n    ) || '_' || TO_CHAR(NOW(), 'MMDD'),\n    LEFT($ct${{ $('CERVEAU_XO').item.json.routing.text_clean }}$ct$, 195),\n    'actif'\nFROM utilisateurs u\nWHERE u.telegram_id = {{ $('CERVEAU_XO').item.json.telegram_chat_id }}\nAND $md${{ $('CERVEAU_XO').item.json.routing.mode }}$md$ = 'qualification'\nON CONFLICT (hashtag) DO UPDATE\n    SET updated_at = NOW()\nRETURNING projet_id, hashtag, nom;",
