        {
          "parameters": {
            "operation": "executeQuery",
            "query": "=WITH latest_project AS (\n    SELECT p.projet_id\n    FROM projets p\n    JOIN utilisateurs u ON u.utilisateur_id = p.utilisateur_id\n    WHERE u.telegram_id = {{ $('CERVEAU_XO').item.json.telegram_chat_id }}\n    AND p.statut = 'actif'\n    ORDER BY p.created_at DESC\n    LIMIT 1\n)\nINSERT INTO sessions (utilisateur_id, projet_id, pole_actif, etat)\nSELECT u.utilisateur_id, lp.projet_id, 'XO', 'ouvert'\nFROM utilisateurs u, latest_project lp\nWHERE u.telegram_id = {{ $('CERVEAU_XO').item.json.telegram_chat_id }}\nAND NOT EXISTS (\n    SELECT 1 FROM sessions s2\n    WHERE s2.utilisateur_id = u.utilisateur_id\n    AND s2.etat = 'ouvert'\n    AND s2.last_activity > NOW() - INTERVAL '24 hours'\n);\n\nUPDATE sessions SET\n    projet_id = (SELECT projet_id FROM latest_project),\n    last_activity = NOW()\nWHERE utilisateur_id = (\n    SELECT utilisateur_id FROM utilisateurs\n    WHERE telegram_id = {{ $('CERVEAU_XO').item.json.telegram_chat_id }}\n)\nAND etat = 'ouvert'\nAND projet_id IS NULL\nAND EXISTS (SELECT 1 FROM latest_project);",
