            "query": "=WITH active_session AS (\n    SELECT s.session_id, s.projet_id\n    FROM sessions s\n    JOIN utilisateurs u ON u.utilisateur_id = s.utilisateur_id\n    WHERE u.telegram_id = {{ $('CERVEAU_XO').item.json.telegram_chat_id }}\n    AND s.etat = 'ouvert'\n    ORDER BY s.last_activity DESC\n    LIMIT 1\n)\nINSERT INTO messages (session_id, projet_id, role, pole_emetteur, contenu, modele_utilise)\nVALUES\n    ((SELECT session_id FROM active_session), (SELECT projet_id FROM active_session),\n     'user', NULL, $xomsg${{ $('CERVEAU_XO').item.json.routing.text_clean }}$xomsg$, NULL),\n    ((SELECT session_id FROM active_session), (SELECT projet_id FROM active_session),\n     'assistant', 'XO', $xomsg${{ $('KORE').item.json.output }}$xomsg$, 'gpt-4o');\n\nUPDATE sessions SET\n    nb_messages = nb_messages + 2,\n    last_activity = NOW()\nWHERE session_id = (\n    SELECT s.session_id FROM sessions s\n    JOIN utilisateurs u ON u.utilisateur_id = s.utilisateur_id\n    WHERE u.telegram_id = {{ $('CERVEAU_XO').item.json.telegram_chat_id }}\n    AND s.etat = 'ouvert'\n    ORDER BY s.last_activity DESC LIMIT 1\n);",
