  'strategie': { workflowRoute: 'strategy',  label: 'P02 Strategie' },
  'market':    { workflowRoute: 'market',    label: 'P03 Marche' },
  'finance':   { workflowRoute: 'finance',   label: 'P04 Finance' },
  'marketing': { workflowRoute: 'strategy',  label: 'P02 Strategie' },
  'produit':   { workflowRoute: 'ideation',  label: 'P01 Ideation' },
  'risk':      { workflowRoute: 'strategy',  label: 'P02 Strategie' }
};
const pole = poles[0] || 'ideation';
const mapped = poleMap[pole] || poleMap['ideation'];
return [{
  json: {
