          "jsCode": "const telegramMsg = $('TELEGRAM_INPUT').item.json;\nconst text = (telegramMsg.message?.text || '').trim();\nconst sessionData = $json;\n\n// Extract hashtags\nconst hashtags = (text.match(/#(\\w+)/g) || []).map(h => h.slice(1).toLowerCase());\nconst poleHashtags = ['finance', 'marketing', 'strategie', 'produit', 'risk', 'ideation', 'market'];\nconst polesActives = hashtags.filter(h => poleHashtags.includes(h));\nconst projetHashtag = hashtags.find(h => !poleHashtags.includes(h));\n\n// Detect route\nlet route = 'agent';\nlet mode = 'dialogue';\n\nif (text.startsWith('/menu')) {\n  route = 'menu';\n} else if (text.startsWith('/reset') || text.toLowerCase() === 'reset') {\n  route = 'reset';\n} else if (polesActives.length > 0) {\n  route = 'pole';\n  mode = 'pole';\n} else if (!sessionData.session_id && !text.startsWith('/')) {\n  route = 'agent';\n  mode = 'qualification';\n} else if (text.toLowerCase().match(/j.ai une id[e\\u00e9]e|et si on|je veux cr[e\\u00e9]er|je veux d[e\\u00e9]velopper/)) {\n  route = 'agent';\n  mode = 'qualification';\n}\n\nreturn [{\n  json: {\n    telegram_chat_id: telegramMsg.message?.chat?.id,\n    routing: {\n      route,\n      mode,\n      poles_actives: polesActives.length > 0 ? polesActives : null,\n      projet_hashtag: projetHashtag || sessionData.projet_actif || null,\n      session_context: sessionData,\n      text_clean: text.replace(/#\\w+/g, '').trim()\n    }\n  }\n}];"
        },
