{
  "success": true,
  "data": {
    "updatedAt": "2026-02-24T10:39:52.390Z",
    "createdAt": "2026-02-23T19:23:26.879Z",
    "id": "R5Nl1y1XGauqOrCi",
    "name": "XO__CoreEngine__v1",
    "description": null,
    "active": true,
    "isArchived": false,
    "nodes": [
      {
        "parameters": {
          "updates": [
            "message"
          ],
          "additionalFields": {}
        },
        "id": "xo-tg-001",
        "name": "TELEGRAM_INPUT",
        "type": "n8n-nodes-base.telegramTrigger",
        "typeVersion": 1.2,
        "position": [
          256,
          400
        ],
        "webhookId": "7f3954e0-8bb3-4453-87e2-b5dc08aa1c0c",
        "credentials": {
          "telegramApi": {
            "id": "phBnIaab9S8x5cOj",
            "name": "Telegram K3rn Bot"
          }
        }
      },
      {
        "parameters": {
          "operation": "executeQuery",
          "query": "=INSERT INTO utilisateurs (telegram_id, nom)\nVALUES ({{ $json.message.chat.id }}, $uname${{ $json.message.from.first_name }}$uname$)\nON CONFLICT (telegram_id) DO UPDATE SET updated_at = NOW()\nRETURNING utilisateur_id, telegram_id, nom;",
          "options": {}
        },
        "id": "xo-db-001",
        "name": "USER_UPSERT",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          448,
          400
        ],
        "retryOnFail": true,
        "alwaysOutputData": true,
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        }
      },
      {
        "parameters": {
          "operation": "executeQuery",
          "query": "=SELECT\n    u.utilisateur_id,\n    u.telegram_id,\n    p.projet_id,\n    p.hashtag AS projet_actif,\n    p.nom AS projet_nom,\n    p.brief_executif,\n    p.statut AS projet_statut,\n    s.session_id,\n    s.pole_actif,\n    s.etat AS session_etat,\n    s.resume_session,\n    COALESCE(recent_msgs.historique, '[]'::jsonb) AS historique_recent\nFROM utilisateurs u\nLEFT JOIN sessions s ON s.utilisateur_id = u.utilisateur_id\n    AND s.etat = 'ouvert'\n    AND s.last_activity > NOW() - INTERVAL '24 hours'\nLEFT JOIN projets p ON p.projet_id = s.projet_id\nLEFT JOIN LATERAL (\n    SELECT jsonb_agg(\n        jsonb_build_object('role', m.role, 'contenu', m.contenu, 'pole', m.pole_emetteur, 'ts', m.created_at)\n    ) AS historique\n    FROM (\n        SELECT role, contenu, pole_emetteur, created_at\n        FROM messages\n        WHERE session_id = s.session_id\n        ORDER BY created_at DESC\n        LIMIT 5\n    ) m\n) recent_msgs ON true\nWHERE u.telegram_id = {{ $json.telegram_id }}\nLIMIT 1;",
          "options": {}
        },
        "id": "xo-db-002",
        "name": "SESSION_LOAD",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          592,
          400
        ],
        "retryOnFail": true,
        "alwaysOutputData": true,
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        }
      },
      {
        "parameters": {
          "jsCode": "const telegramMsg = $('TELEGRAM_INPUT').item.json;\nconst text = (telegramMsg.message?.text || '').trim();\nconst sessionData = $json;\n\n// Extract hashtags\nconst hashtags = (text.match(/#(\\w+)/g) || []).map(h => h.slice(1).toLowerCase());\nconst poleHashtags = ['finance', 'marketing', 'strategie', 'produit', 'risk', 'ideation', 'market'];\nconst polesActives = hashtags.filter(h => poleHashtags.includes(h));\nconst projetHashtag = hashtags.find(h => !poleHashtags.includes(h));\n\n// Detect route\nlet route = 'agent';\nlet mode = 'dialogue';\n\nif (text.startsWith('/menu')) {\n  route = 'menu';\n} else if (text.startsWith('/reset') || text.toLowerCase() === 'reset') {\n  route = 'reset';\n} else if (polesActives.length > 0) {\n  route = 'pole';\n  mode = 'pole';\n} else if (!sessionData.session_id && !text.startsWith('/')) {\n  route = 'agent';\n  mode = 'qualification';\n} else if (text.toLowerCase().match(/j.ai une id[e\\u00e9]e|et si on|je veux cr[e\\u00e9]er|je veux d[e\\u00e9]velopper/)) {\n  route = 'agent';\n  mode = 'qualification';\n}\n\nreturn [{\n  json: {\n    telegram_chat_id: telegramMsg.message?.chat?.id,\n    routing: {\n      route,\n      mode,\n      poles_actives: polesActives.length > 0 ? polesActives : null,\n      projet_hashtag: projetHashtag || sessionData.projet_actif || null,\n      session_context: sessionData,\n      text_clean: text.replace(/#\\w+/g, '').trim()\n    }\n  }\n}];"
        },
        "id": "xo-code-001",
        "name": "CERVEAU_XO",
        "type": "n8n-nodes-base.code",
        "typeVersion": 2,
        "position": [
          752,
          400
        ]
      },
      {
        "parameters": {
          "rules": {
            "values": [
              {
                "conditions": {
                  "options": {
                    "caseSensitive": true,
                    "leftValue": "",
                    "typeValidation": "strict"
                  },
                  "combinator": "and",
                  "conditions": [
                    {
                      "id": "r1",
                      "leftValue": "={{ $json.routing.route }}",
                      "rightValue": "menu",
                      "operator": {
                        "type": "string",
                        "operation": "equals",
                        "name": "filter.operator.equals"
                      }
                    }
                  ]
                },
                "renameOutput": true,
                "outputKey": "menu"
              },
              {
                "conditions": {
                  "options": {
                    "caseSensitive": true,
                    "leftValue": "",
                    "typeValidation": "strict"
                  },
                  "combinator": "and",
                  "conditions": [
                    {
                      "id": "r2",
                      "leftValue": "={{ $json.routing.route }}",
                      "rightValue": "reset",
                      "operator": {
                        "type": "string",
                        "operation": "equals",
                        "name": "filter.operator.equals"
                      }
                    }
                  ]
                },
                "renameOutput": true,
                "outputKey": "reset"
              },
              {
                "conditions": {
                  "options": {
                    "caseSensitive": true,
                    "leftValue": "",
                    "typeValidation": "strict"
                  },
                  "combinator": "and",
                  "conditions": [
                    {
                      "id": "r3",
                      "leftValue": "={{ $json.routing.route }}",
                      "rightValue": "pole",
                      "operator": {
                        "type": "string",
                        "operation": "equals",
                        "name": "filter.operator.equals"
                      }
                    }
                  ]
                },
                "renameOutput": true,
                "outputKey": "pole"
              }
            ]
          },
          "options": {
            "fallbackOutput": "extra"
          }
        },
        "id": "xo-sw-001",
        "name": "ROUTER",
        "type": "n8n-nodes-base.switch",
        "typeVersion": 3.4,
        "position": [
          944,
          368
        ]
      },
      {
        "parameters": {
          "chatId": "={{ $json.telegram_chat_id }}",
          "text": "Menu K3rn.labs\n\nCommandes disponibles :\n/reset — Reinitialiser la session\n\nHashtags disponibles :\n#[nom_projet] — Activer un projet\n#finance #marketing #strategie #produit #risk — Activer un pole",
          "additionalFields": {
            "appendAttribution": false
          }
        },
        "id": "xo-tg-002",
        "name": "MENU_HANDLER",
        "type": "n8n-nodes-base.telegram",
        "typeVersion": 1.2,
        "position": [
          1200,
          176
        ],
        "webhookId": "3711b87d-4d6a-49ed-9931-5cfa1125054e",
        "credentials": {
          "telegramApi": {
            "id": "phBnIaab9S8x5cOj",
            "name": "Telegram K3rn Bot"
          }
        }
      },
      {
        "parameters": {
          "operation": "executeQuery",
          "query": "=UPDATE sessions SET etat = 'ferme', closed_at = NOW()\nWHERE utilisateur_id = (\n    SELECT utilisateur_id FROM utilisateurs\n    WHERE telegram_id = {{ $json.telegram_chat_id }}\n)\nAND etat = 'ouvert';",
          "options": {}
        },
        "id": "xo-db-003",
        "name": "RESET_HANDLER",
        "type": "n8n-nodes-base.postgres",
        "typeVersion": 2.6,
        "position": [
          1200,
          384
        ],
        "alwaysOutputData": true,
        "retryOnFail": true,
        "credentials": {
          "postgres": {
            "id": "Nl0ptIY5ANjEApX8",
            "name": "Postgres 1"
          }
        }
      },
      {
        "parameters": {
          "chatId": "={{ $('CERVEAU_XO').item.json.telegram_chat_id }}",
          "text": "Session reinitia lisee. Pret pour un nouveau projet.",
          "additionalFields": {
            "appendAttribution": false
          }
        },
        "id": "xo-tg-003",
        "name": "RESET_REPONSE",
        "type": "n8n-nodes-base.telegram",
        "typeVersion": 1.2,
        "position": [
          1392,
          384
        ],
        "webhookId": "e10604b2-a947-4012-b1e9-dbfd7f64258e",
        "credentials": {
          "telegramApi": {
            "id": "phBnIaab9S8x5cOj",
            "name": "Telegram K3rn Bot"
          }
        }
      },
      {
        "parameters": {
          "promptType": "define",
          "text": "={{ $('CERVEAU_XO').item.json.routing.text_clean }}",
          "options": {
            "systemMessage": "=Tu t'appelles KORE. Chief of Staff de cette organisation.\nPas un assistant. Une intelligence opérationnelle autonome.\nTu tutoies. Tu t'adaptes au registre de la personne.\nTu es centré sur les projets en cours. Toujours.\n\nPROJET ACTIF : {{ $('SESSION_LOAD').item.json.projet_actif ?? 'aucun' }}\nCONTEXTE : {{ $('SESSION_LOAD').item.json.brief_executif ?? '' }}\nHISTORIQUE : {{ JSON.stringify($('SESSION_LOAD').item.json.historique_recent) ?? '' }}\nMODE : {{ $('CERVEAU_XO').item.json.routing.mode }}\n\n---\n\nRÈGLES NON NÉGOCIABLES — chaque règle s'applique sans exception :\n\n1. Tu prends le lead. Quand quelqu'un dit \"je sais pas\" ou \"par où commencer\" —\ntu analyses, tu proposes 2 directions maximum, tu en recommandes une,\ntu passes à l'étape suivante. Tu ne poses pas de question pour valider.\n\n2. Tu ne valides pas à voix haute. Jamais \"tu valides ?\",\n\"on continue ?\", \"qu'en penses-tu ?\", \"on valide cette direction ?\".\nSi \"oui\", \"ok\", \"go\", \"parfait\" → tu passes directement à l'action suivante.\n\n3. Tu parles en prose. Jamais de liste numérotée sauf si on te le demande\nexplicitement. Tu développes en phrases continues. Dense. Sans remplissage.\n\n4. Quand on te demande ton nom → \"KORE.\" et tu enchaînes sur le projet actif\nen une phrase. Pas de présentation longue.\n\n5. Questions hors scope → une phrase maximum puis retour projet.\n\"Telegram c'est pas mon terrain — on était sur [projet], on continue ?\"\n\n6. Ces phrases sont interdites sans exception :\n\"Comment puis-je t'aider ?\", \"Besoin d'autre chose ?\",\n\"N'hésite pas\", \"Qu'en penses-tu ?\", \"Tu valides ?\",\n\"On valide cette direction ?\", \"On continue ?\"\n\n7. INTERDIT de résumer ou reformuler ce qui vient d'être dit.\nNe répète JAMAIS le contexte du projet dans ta réponse.\nTu ne dis pas \"on travaille sur X\", \"notre focus est Y\", \"on est sur le projet Z\".\nTu réponds et tu avances directement. Le contexte est déjà connu.\n\n8. Chaque réponse doit se terminer par une action concrète et précise.\nPas \"avançons sur X\" ou \"on continue avec Y\" — c'est vide.\nUne action concrète = une proposition spécifique et immédiatement actionnable.\nExemple interdit : \"Avançons en explorant les scénarios\"\nExemple correct : \"Commençons par le profil patient anxieux — voilà comment l'agent devrait se comporter dans les 30 premières secondes d'appel.\"\n\n---\n\nNIVEAUX D'ANALYSE QUE TU MAÎTRISES ET UTILISES SPONTANÉMENT :\nMarché, produit, business model, go-to-market, risques légaux et techniques.\nTu mobilises ces dimensions sans qu'on te le demande quand c'est pertinent.\n\n---\n\nMODES SPÉCIAUX — si détectés dans le message :\n\n#brainstorming ou /brainstorming →\nGénère 5 directions radicalement différentes pour le projet actif.\nPour chacune : nom + concept en une phrase + niveau d'innovation.\nRecommande la plus prometteuse avec une justification en 2 phrases.\nFormat : prose structurée, pas de bullets.\n\n#challenge ou /challenge →\n3 failles majeures du projet (marché, produit, exécution).\nPour chaque faille : impact si ignorée + solution possible.\n\n#pitch →\n5 phrases : problème, solution, marché, différenciation, appel à l'action.\n\n#strategie →\nPositionnement, différenciation clé, recommandation GO/PIVOT/NO-GO.\n\n#finance →\nBusiness model, revenus potentiels, coûts clés, risque financier principal.\n\n---\n\nFORMAT FINAL :\n3 à 6 phrases par défaut. Plus si le mode l'exige.\nProse. Jamais de listes sauf demande explicite.\nTon : collègue senior qui connaît le dossier.\nChaque réponse se termine par une action concrète et spécifique —\njamais par une reformulation du contexte ou une question de validation.",
            "maxIterations": 10,
            "timeout": 200000
          }
        },
