parameters.jsCode:
const msg = $('TELEGRAM_INPUT').item.json;
const callbackQuery = msg.callback_query ?? null;
const text = (msg.message?.text || callbackQuery?.data || '').trim();
const sessionData = $json;
const chatId = msg.message?.chat?.id ?? callbackQuery?.message?.chat?.id;

// 1. MODES SPECIAUX (hashtag ou commande slash)
const specialModes = ['brainstorming','challenge','strategie','finance','pitch','market','status'];
const detectedSpecial = specialModes.find(m =>
  text.toLowerCase().includes('#' + m) ||
  text.toLowerCase().includes('/' + m)
);
if (detectedSpecial) {
  return [{ json: {
    telegram_chat_id: chatId,
    is_callback: !!callbackQuery,
    callback_id: callbackQuery?.id ?? null,
    routing: {
      route: 'agent',
      mode: detectedSpecial,
      poles_actives: null,
      projet_hashtag: sessionData.projet_actif ?? null,
      session_context: sessionData,
      text_clean: text
    }
  }}];
}

// 2. COMMANDES STRUCTUREES
if (text.startsWith('/start') || text.startsWith('/menu')) {
  return [{ json: {
    telegram_chat_id: chatId,
    is_callback: !!callbackQuery,
    callback_id: callbackQuery?.id ?? null,
    routing: { route: 'menu', mode: 'menu', session_context: sessionData, text_clean: text }
  }}];
}
if (text.startsWith('/reset') || text.toLowerCase() === 'reset') {
  return [{ json: {
    telegram_chat_id: chatId,
    is_callback: false,
    callback_id: null,
    routing: { route: 'reset', mode: 'reset', session_context: sessionData, text_clean: text }
  }}];
}
if (text.startsWith('/projets')) {
  return [{ json: {
    telegram_chat_id: chatId,
    is_callback: false,
    callback_id: null,
    routing: { route: 'projets', mode: 'projets', session_context: sessionData, text_clean: text }
  }}];
}
if (text.startsWith('/aide')) {
  return [{ json: {
    telegram_chat_id: chatId,
    is_callback: false,
    callback_id: null,
    routing: { route: 'aide', mode: 'aide', session_context: sessionData, text_clean: text }
  }}];
}

// 3. CALLBACK QUERY (bouton inline)
if (callbackQuery) {
  const data = callbackQuery.data;
  if (data.startsWith('projet:')) {
    const hashtag = data.replace('projet:', '');
    return [{ json: {
      telegram_chat_id: chatId,
      is_callback: true,
      callback_id: callbackQuery.id,
      routing: {
        route: 'agent',
        mode: 'projet_select',
        projet_hashtag: hashtag,
        session_context: sessionData,
        text_clean: 'Charge le projet ' + hashtag,
        poles_actives: null
      }
    }}];
  }
  if (data === 'menu') {
    return [{ json: {
      telegram_chat_id: chatId,
      is_callback: true,
      callback_id: callbackQuery.id,
      routing: { route: 'menu', mode: 'menu', session_context: sessionData, text_clean: 'menu' }
    }}];
  }
  if (data === 'projets') {
    return [{ json: {
      telegram_chat_id: chatId,
      is_callback: true,
      callback_id: callbackQuery.id,
      routing: { route: 'projets', mode: 'projets', session_context: sessionData, text_clean: 'projets' }
    }}];
  }
  if (data === 'aide') {
    return [{ json: {
      telegram_chat_id: chatId,
      is_callback: true,
      callback_id: callbackQuery.id,
      routing: { route: 'aide', mode: 'aide', session_context: sessionData, text_clean: 'aide' }
    }}];
  }
  // Callback generique -> dialogue
  return [{ json: {
    telegram_chat_id: chatId,
    is_callback: true,
    callback_id: callbackQuery.id,
    routing: {
      route: 'agent', mode: 'dialogue',
      session_context: sessionData,
      text_clean: data,
      poles_actives: null,
      projet_hashtag: sessionData.projet_actif ?? null
    }
  }}];
}

// 4. HASHTAGS POLES
const hashtags = (text.match(/#(\w+)/g) || []).map(h => h.slice(1).toLowerCase());
const poleHashtags = ['marketing','produit','risk','ideation'];
const polesActives = hashtags.filter(h => poleHashtags.includes(h));
const projetHashtag = hashtags.find(h => !poleHashtags.includes(h));

// 5. DETECTION MODE
let route = 'agent';
let mode = 'dialogue';
if (polesActives.length > 0) { route = 'pole'; mode = 'pole'; }
else if (!sessionData.session_id && !text.startsWith('/')) { route = 'agent'; mode = 'qualification'; }
else if (text.toLowerCase().match(/j.ai une id[eé]e|et si on|je veux (cr[eé]er|d[eé]velopper|lancer)/)) { route = 'agent'; mode = 'qualification'; }

return [{ json: {
  telegram_chat_id: chatId,
  is_callback: false,
  callback_id: null,
  routing: {
    route, mode,
    poles_actives: polesActives.length > 0 ? polesActives : null,
    projet_hashtag: projetHashtag || sessionData.projet_actif || null,
    session_context: sessionData,
    text_clean: text.replace(/#\w+/g, '').trim()
  }
}}];

const routing = $('CERVEAU_XO').item.json;
const sessionData = routing.routing.session_context;
const nom = sessionData.nom ?? 'toi';
const projetActif = sessionData.projet_actif ?? null;
const projetNom = sessionData.projet_nom ?? null;

let texte = `Bonjour ${nom} — voici ton tableau de bord.`;
if (projetActif) {
  texte += `\n\nProjet actif : *${projetNom || projetActif}*`;
} else {
  texte += `\n\nAucun projet actif. Envoie-moi ton idée pour commencer.`;
}
texte += `\n\nHashtags disponibles : #brainstorming #challenge #pitch #strategie #finance #market #status`;

const keyboard = {
  inline_keyboard: [
    [
      { text: '📁 Mes projets', callback_data: 'projets' },
      { text: '❓ Aide', callback_data: 'aide' }
    ],
    [
      { text: '🔄 Reset session', callback_data: 'reset' }
    ]
  ]
};

return [{ json: {
  telegram_chat_id: routing.telegram_chat_id,
  text: texte,
  reply_markup: JSON.stringify(keyboard),
  callback_id: routing.callback_id
}}];

parameters.query:
=UPDATE sessions SET etat = 'ferme', closed_at = NOW()
WHERE utilisateur_id = (
    SELECT utilisateur_id FROM utilisateurs
    WHERE telegram_id = {{ $json.telegram_chat_id }}
)
AND etat = 'ouvert';

parameters.jsCode:
const items = $input.all();
const chatId = $('CERVEAU_XO').item.json.telegram_chat_id;

if (!items.length || !items[0].json.projet_id) {
  return [{ json: {
    telegram_chat_id: chatId,
    text: 'Aucun projet actif pour le moment. Envoie-moi ton idée pour en créer un.',
    reply_markup: null
  }}];
}

const rows = items.map(item => ({
  projet_id: item.json.projet_id,
  hashtag: item.json.hashtag,
  nom: item.json.nom
}));

// Construire InlineKeyboard — 1 bouton par projet (max 8)
const keyboard_rows = [];
for (let i = 0; i < rows.length; i += 2) {
  const rowBtns = [];
  rowBtns.push({ text: rows[i].nom.substring(0, 30), callback_data: 'projet:' + rows[i].hashtag });
  if (rows[i+1]) rowBtns.push({ text: rows[i+1].nom.substring(0, 30), callback_data: 'projet:' + rows[i+1].hashtag });
  keyboard_rows.push(rowBtns);
}
