parameters.jsCode:
const msg = $('TELEGRAM_INPUT').item.json;
const callbackQuery = msg.callback_query ?? null;
const text = (msg.message?.text || callbackQuery?.data || '').trim();
const sessionData = $json;
const chatId = msg.message?.chat?.id ?? callbackQuery?.message?.chat?.id;

// 1. MODES SPECIAUX (hashtag ou commande slash)
const specialModes = ['brainstorming','challenge','strategie','finance','pitch','market','status'];
const detectedSpecial = specialModes.find(m =>
  text.toLowerCase().includes('#' + m) ||
  text.toLowerCase().includes('/' + m)
);
if (detectedSpecial) {
  return [{ json: {
    telegram_chat_id: chatId,
    is_callback: !!callbackQuery,
    callback_id: callbackQuery ? callbackQuery.id : null,
    routing: {
      route: 'agent', mode: detectedSpecial,
      poles_actives: null,
      projet_hashtag: sessionData.projet_actif ?? null,
      session_context: sessionData, text_clean: text
    }
  }}];
}

// 2. COMMANDES STRUCTUREES
if (text.startsWith('/start') || text.startsWith('/menu')) {
  return [{ json: {
    telegram_chat_id: chatId, is_callback: !!callbackQuery,
    callback_id: callbackQuery ? callbackQuery.id : null,
    routing: { route: 'menu', mode: 'menu', session_context: sessionData, text_clean: text }
  }}];
}
if (text.startsWith('/reset') || text.toLowerCase() === 'reset') {
  return [{ json: {
    telegram_chat_id: chatId, is_callback: false, callback_id: null,
    routing: { route: 'reset', mode: 'reset', session_context: sessionData, text_clean: text }
  }}];
}
if (text.startsWith('/projets')) {
  return [{ json: {
    telegram_chat_id: chatId, is_callback: false, callback_id: null,
    routing: { route: 'projets', mode: 'projets', session_context: sessionData, text_clean: text }
  }}];
}
if (text.startsWith('/aide')) {
  return [{ json: {
    telegram_chat_id: chatId, is_callback: false, callback_id: null,
    routing: { route: 'aide', mode: 'aide', session_context: sessionData, text_clean: text }
  }}];
}

// 3. CALLBACK QUERY (bouton inline)
if (callbackQuery) {
  const data = callbackQuery.data;
  if (data.startsWith('projet:')) {
    const hashtag = data.replace('projet:', '');
    return [{ json: {
      telegram_chat_id: chatId, is_callback: true, callback_id: callbackQuery.id,
      routing: {
        route: 'agent', mode: 'projet_select', projet_hashtag: hashtag,
        session_context: sessionData,
        text_clean: 'Charge le projet ' + hashtag, poles_actives: null
      }
    }}];
  }
  if (data === 'menu') {
    return [{ json: {
      telegram_chat_id: chatId, is_callback: true, callback_id: callbackQuery.id,
      routing: { route: 'menu', mode: 'menu', session_context: sessionData, text_clean: 'menu' }
    }}];
  }
  if (data === 'projets') {
    return [{ json: {
      telegram_chat_id: chatId, is_callback: true, callback_id: callbackQuery.id,
      routing: { route: 'projets', mode: 'projets', session_context: sessionData, text_clean: 'projets' }
    }}];
  }
  if (data === 'aide') {
    return [{ json: {
      telegram_chat_id: chatId, is_callback: true, callback_id: callbackQuery.id,
      routing: { route: 'aide', mode: 'aide', session_context: sessionData, text_clean: 'aide' }
    }}];
  }
  // Callback reset
  if (data === 'reset') {
    return [{ json: {
      telegram_chat_id: chatId, is_callback: true, callback_id: callbackQuery.id,
      routing: { route: 'reset', mode: 'reset', session_context: sessionData, text_clean: 'reset' }
    }}];
  }
  // Callback generique -> dialogue
  return [{ json: {
    telegram_chat_id: chatId, is_callback: true, callback_id: callbackQuery.id,
    routing: {
      route: 'agent', mode: 'dialogue', session_context: sessionData,
      text_clean: data, poles_actives: null,
      projet_hashtag: sessionData.projet_actif ?? null
    }
  }}];
}

// 4. HASHTAGS POLES
const hashtags = (text.match(/#(\w+)/g) || []).map(h => h.slice(1).toLowerCase());
const poleHashtags = ['marketing','produit','risk','ideation'];
const polesActives = hashtags.filter(h => poleHashtags.includes(h));
const projetHashtag = hashtags.find(h => !poleHashtags.includes(h));

// 5. DETECTION MODE
let route = 'agent';
let mode = 'dialogue';
if (polesActives.length > 0) {
  route = 'pole'; mode = 'pole';
} else if (!sessionData.session_id && !text.startsWith('/') && !text.startsWith('#') && text.length >= 20) {
  // CORRECTION 2 : qualification seulement si message substantiel
  route = 'agent'; mode = 'qualification';
} else if (text.toLowerCase().match(/j.ai une id[e\u00e9]e|et si on|je veux (cr[e\u00e9]er|d[e\u00e9]velopper|lancer)/) && text.length >= 20) {
  route = 'agent'; mode = 'qualification';
}

return [{ json: {
  telegram_chat_id: chatId,
  is_callback: false, callback_id: null,
  routing: {
    route, mode,
    poles_actives: polesActives.length > 0 ? polesActives : null,
    projet_hashtag: projetHashtag || sessionData.projet_actif || null,
    session_context: sessionData,
    text_clean: text.replace(/#\w+/g, '').trim()
  }
}}];

