        "parameters": {
          "jsCode": "const routing = $('CERVEAU_XO').item.json;\nconst sessionData = routing.routing.session_context;\nconst nom = sessionData.nom ?? 'toi';\nconst projetActif = sessionData.projet_actif ?? null;\nconst projetNom = sessionData.projet_nom ?? null;\n\nlet texte = `Bonjour ${nom} — voici ton tableau de bord.`;\nif (projetActif) {\n  texte += `\\n\\nProjet actif : *${projetNom || projetActif}*`;\n} else {\n  texte += `\\n\\nAucun projet actif. Envoie-moi ton idée pour commencer.`;\n}\ntexte += `\\n\\nHashtags disponibles : #brainstorming #challenge #pitch #strategie #finance #market #status`;\n\nconst keyboard = {\n  inline_keyboard: [\n    [\n      { text: '📁 Mes projets', callback_data: 'projets' },\n      { text: '❓ Aide', callback_data: 'aide' }\n    ],\n    [\n      { text: '🔄 Reset session', callback_data: 'reset' }\n    ]\n  ]\n};\n\nreturn [{ json: {\n  telegram_chat_id: routing.telegram_chat_id,\n  text: texte,\n  reply_markup: JSON.stringify(keyboard),\n  callback_id: routing.callback_id\n}}];"
