        "parameters": {
          "jsCode": "const items = $input.all();\nconst chatId = $('CERVEAU_XO').item.json.telegram_chat_id;\n\nif (!items.length || !items[0].json.projet_id) {\n  return [{ json: {\n    telegram_chat_id: chatId,\n    text: 'Aucun projet actif pour le moment. Envoie-moi ton idée pour en créer un.',\n    reply_markup: null\n  }}];\n}\n\nconst rows = items.map(item => ({\n  projet_id: item.json.projet_id,\n  hashtag: item.json.hashtag,\n  nom: item.json.nom\n}));\n\n// Construire InlineKeyboard — 1 bouton par projet (max 8)\nconst keyboard_rows = [];\nfor (let i = 0; i < rows.length; i += 2) {\n  const rowBtns = [];\n  rowBtns.push({ text: rows[i].nom.substring(0, 30), callback_data: 'projet:' + rows[i].hashtag });\n  if (rows[i+1]) rowBtns.push({ text: rows[i+1].nom.substring(0, 30), callback_data: 'projet:' + rows[i+1].hashtag });\n  keyboard_rows.push(rowBtns);\n}\nkeyboard_rows.push([{ text: '⬅️ Menu', callback_data: 'menu' }]);\n\nconst keyboard = { inline_keyboard: keyboard_rows };\nconst liste = rows.map(r => `• *${r.nom}* — #${r.hashtag}`).join('\\n');\n\nreturn [{ json: {\n  telegram_chat_id: chatId,\n  text: `Tes projets actifs :\\n\\n${liste}\\n\\nClique pour activer un projet.`,\n  reply_markup: JSON.stringify(keyboard)\n}}];"
