parameters.jsCode:
const items = $input.all();
const chatId = $('CERVEAU_XO').item.json.telegram_chat_id;

if (!items.length || !items[0].json.projet_id) {
  return [{ json: {
    telegram_chat_id: chatId,
    text: 'Aucun projet actif pour le moment. Envoie-moi ton idée pour en créer un.',
    reply_markup: null
  }}];
}

const rows = items.map(item => ({
  projet_id: item.json.projet_id,
  hashtag: item.json.hashtag,
  nom: item.json.nom
}));

const keyboard_rows = [];
for (let i = 0; i < rows.length; i += 2) {
  const rowBtns = [];
  rowBtns.push({ text: rows[i].nom.substring(0, 30), callback_data: 'projet:' + rows[i].hashtag });
  if (rows[i+1]) rowBtns.push({ text: rows[i+1].nom.substring(0, 30), callback_data: 'projet:' + rows[i+1].hashtag });
  keyboard_rows.push(rowBtns);
}
keyboard_rows.push([{ text: '⬅️ Menu', callback_data: 'menu' }]);

const keyboard = { inline_keyboard: keyboard_rows };
const liste = rows.map(r => `• *${r.nom}* — #${r.hashtag}`).join('\n');

return [{ json: {
  telegram_chat_id: chatId,
  text: `Tes projets actifs :\n\n${liste}\n\nClique pour activer un projet.`,
  reply_markup: JSON.stringify(keyboard)
}}];

const routing = $('CERVEAU_XO').item.json.routing;
const sessionCtx = routing.session_context;
const poles = routing.poles_actives || [];
const poleMap = {
  'ideation':  { workflowRoute: 'ideation',  label: 'P01 Ideation' },
  'strategie': { workflowRoute: 'strategy',  label: 'P02 Strategie' },
  'market':    { workflowRoute: 'market',    label: 'P03 Marche' },
  'finance':   { workflowRoute: 'finance',   label: 'P04 Finance' },
  'marketing': { workflowRoute: 'strategy',  label: 'P02 Strategie' },
  'produit':   { workflowRoute: 'ideation',  label: 'P01 Ideation' },
  'risk':      { workflowRoute: 'strategy',  label: 'P02 Strategie' }
};
const pole = poles[0] || 'ideation';
const mapped = poleMap[pole] || poleMap['ideation'];
return [{
  json: {
    telegram_chat_id: $('CERVEAU_XO').item.json.telegram_chat_id,
    pole_actif: pole,
    pole_label: mapped.label,
    workflow_route: mapped.workflowRoute,
    query: routing.text_clean,
    projet_hashtag: routing.projet_hashtag,
    session_id: sessionCtx.session_id,
    projet_id: sessionCtx.projet_id
  }
}];

